INSERT INTO engine_bug_queue (bug_class, title, severity, owner_cluster, root_cause, prevention_rule, probe_type, probe_logic, status, concepts_affected, fixed_in_files, discovered_in_session, row_type) VALUES
('gss_dist_vector_drifts_under_camera_orbit', 'The d distance line swings sideways (detaches from the geometry) when the teacher orbits the camera — a normal-aligned distance vector must be anchored to the sheet normal in world space, NEVER billboarded camera-right', 'MAJOR', 'peter_parker:renderer_primitives', 'The gss_dist_vector (the white "d" ruler from the sheet to the field point P) was billboarded to camera-right (copied from gauss_law_line''s radial r ruler). For the LINE, r is radial (any direction in the plane ⊥ to the wire) so billboarding to a consistent screen-right reads cleanly. For the SHEET, d lies along the FIXED sheet normal (±X) — a single physical direction. Billboarding it makes the d line swing away from the normal as the camera orbits, so it appears to "move sideways" and detach from the sheet→P geometry. This CORRECTS the build-time rule gss_two_distinct_reference_lines_d_billboarded_H_axial, which prescribed billboarding d — wrong for a planar/normal-aligned distance.', 'For a planar/constant-field sibling, the perpendicular-distance ruler (d) and the pillbox half-height ruler (H) must be drawn along their FIXED world directions (the sheet normal / pillbox axis) so they stay STATIC and attached to the geometry under camera orbit — never billboarded camera-right. Billboarding is correct ONLY for a radial ruler (the line''s r), never for a normal-aligned one. The d ruler runs sheet-surface → P along the world normal; as the camera orbits it rotates WITH the scene, never independently.', 'manual', 'Open any gauss_law_sheet state showing the d line, enter Move/orbit mode, and rotate the camera; the d ruler must stay pinned to the sheet→P geometry (rotating with the scene), never swing sideways to stay screen-horizontal.', 'FIXED', ARRAY['gauss_law_sheet'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-26_gauss_sheet_founder_review', 'incident'),
('gss_d_label_sits_below_the_distance_line', 'The "d" label should sit BELOW the d ruler (near its midpoint), not crowd the field point P', 'MODERATE', 'peter_parker:renderer_primitives', 'The "d" text label rendered beside/near the P tip, crowding the P marker instead of clearly labelling the distance ruler. The teacher asked for "d below the line exactly here".', 'Place the gss distance-ruler label ("d") just BELOW the midpoint of the d line (offset along -up in screen space), clearly separated from the P tip marker, so the ruler reads "this length is d" at a glance.', 'manual', 'Open a gauss_law_sheet state with the d line; the "d" label sits below the ruler near its middle, not overlapping the P dot.', 'FIXED', ARRAY['gauss_law_sheet'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-26_gauss_sheet_founder_review', 'incident'),
('gss_flux_bearing_caps_need_stronger_glow', 'The two flat circular pillbox CAPS (the flux-bearing faces) must glow more — a brighter emissive disk + a glowing rim ring — so the eye reads the caps as where the flux leaves', 'MODERATE', 'peter_parker:renderer_primitives', 'The pillbox cap disks rendered as faint translucent circles, so the flux-bearing faces (the SUPPORTING-aha payoff: caps pierce, wall grazes) did not stand out. The teacher asked for "a light glowing around the circle" on the cap surfaces.', 'In the planar pillbox, the two flat caps are the flux-bearing faces — give them a stronger glow than the curved wall: a brighter emissive/opacity on the cap disk PLUS a glowing rim ring around each cap circle, brightened on the caps-flux beat (STATE_4) and present whenever the pillbox shows. Rule 29: emphasis is brightness/glow, never a size pulse.', 'manual', 'Open STATE_3/STATE_4; each flat circular cap reads with a clear glow (disk + rim ring) distinctly brighter than the curved wall, marking the caps as the flux-bearing faces.', 'FIXED', ARRAY['gauss_law_sheet'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-26_gauss_sheet_founder_review', 'incident')
